/*
 * COMP 421 Lab 2: Yalnix Kernel
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>

#include <comp421/hardware.h>
#include <comp421/yalnix.h>
#include <comp421/loadinfo.h>

/* ============================================================
 * Constants
 * ============================================================ */
#define MAX_PROCESSES    128
#define CLOCK_QUANTUM    2

/* ============================================================
 * Data Structures
 * ============================================================ */

typedef enum {
    PROC_FREE = 0,
    PROC_READY,
    PROC_RUNNING,
    PROC_BLOCKED,
    PROC_ZOMBIE,
    PROC_WAIT_DELAY,
    PROC_WAIT_TTY_READ,
    PROC_WAIT_TTY_WRITE
} ProcState;

typedef struct pcb {
    int pid;
    ProcState state;
    SavedContext ctx;
    struct pte *pt0;
    unsigned long pt0_phys;
    void *brk;
    int clock_ticks;
    int delay_ticks;
    int exit_status;
    int parent_pid;
    struct pcb *next;
    struct zombie_node *zombie_children;
    int num_children;
} PCB;

typedef struct zombie_node {
    int pid;
    int status;
    struct zombie_node *next;
} ZombieNode;

typedef struct tty_buf {
    char data[TERMINAL_MAX_LINE];
    int len;
    int offset;
    struct tty_buf *next;
} TtyBuf;

typedef struct tty_write_req {
    PCB *proc;
    char *buf;
    int len;
    int written;
    struct tty_write_req *next;
} TtyWriteReq;

/* ============================================================
 * Global Variables
 * ============================================================ */

static int vm_enabled = 0;
static void *kernel_brk = NULL;
static int num_phys_pages = 0;

/* Free frame list */
static int *free_frame_list = NULL;
static int num_free_frames = 0;
static int free_frame_capacity = 0;

/* Page tables */
static struct pte *kernel_pt1 = NULL;
static struct pte *initial_pt0 = NULL;
static unsigned long kernel_pt1_phys = 0;

/* Interrupt vector table */
static void (*interrupt_vector[TRAP_VECTOR_SIZE])(ExceptionInfo *);

/* Process table */
static PCB procs[MAX_PROCESSES];
static int next_pid = 0;
static PCB *current_proc = NULL;
static PCB *idle_proc = NULL;

/* Ready queue */
static PCB *ready_head = NULL;
static PCB *ready_tail = NULL;

/* Delay queue */
static PCB *delay_head = NULL;

/* TTY state */
static TtyBuf *tty_input_head[NUM_TERMINALS];
static TtyBuf *tty_input_tail[NUM_TERMINALS];
static PCB *tty_read_waiters[NUM_TERMINALS];
static int tty_transmit_busy[NUM_TERMINALS];
static TtyWriteReq *tty_write_head[NUM_TERMINALS];
static TtyWriteReq *tty_write_tail[NUM_TERMINALS];
static char tty_transmit_buf[NUM_TERMINALS][TERMINAL_MAX_LINE];

/* Idle process setup flag */
static int idle_initialized = 0;

/* Pointer to KernelStart's ExceptionInfo (for idle process return) */
static ExceptionInfo *boot_info = NULL;

/* ============================================================
 * Built-in idle process code
 * ============================================================ */
static void __attribute__((noinline))
DoIdle(void)
{
    while (1) {
        TracePrintf(1, "DoIdle\n");
        Pause();
    }
}

/* ============================================================
 * Free Frame Management
 * ============================================================ */

static void
init_free_frames(int capacity)
{
    free_frame_list = (int *)malloc(capacity * sizeof(int));
    if (!free_frame_list) {
        TracePrintf(0, "init_free_frames: malloc failed\n");
        Halt();
    }
    free_frame_capacity = capacity;
    num_free_frames = 0;
}

static void
add_free_frame(int pfn)
{
    if (num_free_frames >= free_frame_capacity) return;
    free_frame_list[num_free_frames++] = pfn;
}

static int
alloc_frame(void)
{
    if (num_free_frames <= 0) return -1;
    return free_frame_list[--num_free_frames];
}

static int
get_num_free_frames(void)
{
    return num_free_frames;
}

/* ============================================================
 * Queue Management
 * ============================================================ */

static void
enqueue_ready(PCB *p)
{
    p->next = NULL;
    p->state = PROC_READY;
    if (ready_tail) {
        ready_tail->next = p;
    } else {
        ready_head = p;
    }
    ready_tail = p;
}

static PCB *
dequeue_ready(void)
{
    PCB *p = ready_head;
    if (p) {
        ready_head = p->next;
        if (!ready_head) ready_tail = NULL;
        p->next = NULL;
    }
    return p;
}

static void
enqueue_delay(PCB *p)
{
    p->next = delay_head;
    p->state = PROC_WAIT_DELAY;
    delay_head = p;
}

/* ============================================================
 * PCB Management
 * ============================================================ */

static PCB *
alloc_pcb(void)
{
    int pid = next_pid++;
    if (pid >= MAX_PROCESSES) return NULL;
    PCB *p = &procs[pid];
    memset(p, 0, sizeof(PCB));
    p->pid = pid;
    p->state = PROC_FREE;
    p->parent_pid = -1;
    p->brk = (void *)MEM_INVALID_SIZE;
    return p;
}

static PCB *
find_pcb(int pid)
{
    if (pid < 0 || pid >= next_pid) return NULL;
    return &procs[pid];
}

/* ============================================================
 * Page Table Helpers
 * ============================================================ */

static struct pte *
alloc_page_table(unsigned long *phys)
{
    int pfn = alloc_frame();
    if (pfn < 0) return NULL;
    *phys = (unsigned long)pfn << PAGESHIFT;

    int r1_idx;
    struct pte *pt = NULL;
    for (r1_idx = PAGE_TABLE_LEN - 1; r1_idx >= 0; r1_idx--) {
        if (!kernel_pt1[r1_idx].valid) {
            kernel_pt1[r1_idx].valid = 1;
            kernel_pt1[r1_idx].kprot = PROT_READ | PROT_WRITE;
            kernel_pt1[r1_idx].uprot = PROT_NONE;
            kernel_pt1[r1_idx].pfn = pfn;
            WriteRegister(REG_TLB_FLUSH,
                (RCS421RegVal)(VMEM_1_BASE + ((unsigned long)r1_idx << PAGESHIFT)));
            pt = (struct pte *)(unsigned long)(VMEM_1_BASE + ((unsigned long)r1_idx << PAGESHIFT));
            memset(pt, 0, PAGE_TABLE_SIZE);
            break;
        }
    }
    if (!pt) {
        add_free_frame(pfn);
        return NULL;
    }
    return pt;
}

static int
count_user_pages(struct pte *pt0)
{
    int count = 0;
    int kstack_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
    int i;
    for (i = 0; i < kstack_base_vpn; i++) {
        if (pt0[i].valid) count++;
    }
    return count;
}

/* ============================================================
 * Context Switch Functions
 * ============================================================ */

static SavedContext *
MySwitchFunc(SavedContext *ctxp, void *p1, void *p2)
{
    PCB *old_proc = (PCB *)p1;
    PCB *new_proc = (PCB *)p2;
    old_proc->ctx = *ctxp;
    WriteRegister(REG_PTR0, (RCS421RegVal)new_proc->pt0_phys);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    return &new_proc->ctx;
}

static SavedContext *
CloneInitFunc(SavedContext *ctxp, void *p1, void *p2)
{
    PCB *old_proc = (PCB *)p1;
    PCB *new_proc = (PCB *)p2;
    old_proc->ctx = *ctxp;
    new_proc->ctx = *ctxp;

    int kstack_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
    int i;
    int temp_idx = -1;
    for (i = PAGE_TABLE_LEN - 1; i >= 0; i--) {
        if (!kernel_pt1[i].valid) { temp_idx = i; break; }
    }
    if (temp_idx < 0) return ctxp;

    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int vpn = kstack_base_vpn + i;
        unsigned int dst_pfn = new_proc->pt0[vpn].pfn;
        kernel_pt1[temp_idx].valid = 1;
        kernel_pt1[temp_idx].kprot = PROT_READ | PROT_WRITE;
        kernel_pt1[temp_idx].uprot = PROT_NONE;
        kernel_pt1[temp_idx].pfn = dst_pfn;
        WriteRegister(REG_TLB_FLUSH,
            (RCS421RegVal)(VMEM_1_BASE + ((unsigned long)temp_idx << PAGESHIFT)));
        memcpy((void *)(unsigned long)(VMEM_1_BASE + ((unsigned long)temp_idx << PAGESHIFT)),
               (void *)((unsigned long)vpn << PAGESHIFT), PAGESIZE);
    }
    kernel_pt1[temp_idx].valid = 0;
    WriteRegister(REG_TLB_FLUSH,
        (RCS421RegVal)(VMEM_1_BASE + ((unsigned long)temp_idx << PAGESHIFT)));

    return &old_proc->ctx;
}

static SavedContext *
ForkSwitchFunc(SavedContext *ctxp, void *p1, void *p2)
{
    PCB *parent = (PCB *)p1;
    PCB *child = (PCB *)p2;
    parent->ctx = *ctxp;
    child->ctx = *ctxp;

    int i;
    int temp_idx = -1;
    for (i = PAGE_TABLE_LEN - 1; i >= 0; i--) {
        if (!kernel_pt1[i].valid) { temp_idx = i; break; }
    }
    if (temp_idx < 0) return ctxp;

    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        if (parent->pt0[i].valid) {
            kernel_pt1[temp_idx].valid = 1;
            kernel_pt1[temp_idx].kprot = PROT_READ | PROT_WRITE;
            kernel_pt1[temp_idx].uprot = PROT_NONE;
            kernel_pt1[temp_idx].pfn = child->pt0[i].pfn;
            WriteRegister(REG_TLB_FLUSH,
                (RCS421RegVal)(VMEM_1_BASE + ((unsigned long)temp_idx << PAGESHIFT)));

            unsigned int old_kprot = parent->pt0[i].kprot;
            if (!(old_kprot & PROT_READ)) {
                parent->pt0[i].kprot = PROT_READ | PROT_WRITE;
                WriteRegister(REG_TLB_FLUSH,
                    (RCS421RegVal)((unsigned long)i << PAGESHIFT));
            }
            memcpy((void *)(unsigned long)(VMEM_1_BASE + ((unsigned long)temp_idx << PAGESHIFT)),
                   (void *)((unsigned long)i << PAGESHIFT), PAGESIZE);
            if (!(old_kprot & PROT_READ)) {
                parent->pt0[i].kprot = old_kprot;
                WriteRegister(REG_TLB_FLUSH,
                    (RCS421RegVal)((unsigned long)i << PAGESHIFT));
            }
        }
    }
    kernel_pt1[temp_idx].valid = 0;
    WriteRegister(REG_TLB_FLUSH,
        (RCS421RegVal)(VMEM_1_BASE + ((unsigned long)temp_idx << PAGESHIFT)));

    return &parent->ctx;
}

/* ============================================================
 * Schedule / Context Switch to Next Process
 * ============================================================ */

static void
schedule(ExceptionInfo *info)
{
    (void)info;
    PCB *next = dequeue_ready();
    if (!next) {
        if (current_proc == idle_proc) return;
        next = idle_proc;
    }
    if (next == current_proc) return;

    PCB *old = current_proc;
    current_proc = next;
    next->state = PROC_RUNNING;
    next->clock_ticks = 0;
    ContextSwitch(MySwitchFunc, &old->ctx, (void *)old, (void *)next);
}

/* ============================================================
 * Check for remaining live processes; Halt if none
 * ============================================================ */
static int
any_live_processes(void)
{
    int j;
    for (j = 0; j < next_pid; j++) {
        if (j == idle_proc->pid) continue;
        if (procs[j].state != PROC_FREE && procs[j].state != PROC_ZOMBIE) return 1;
    }
    return 0;
}

/* ============================================================
 * Terminate Process Helper
 * ============================================================ */

static void
terminate_process(PCB *proc, int status)
{
    TracePrintf(0, "terminate_process: pid %d, status %d\n", proc->pid, status);

    int kstack_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
    int i;

    /* Free user Region 0 pages */
    for (i = 0; i < kstack_base_vpn; i++) {
        if (proc->pt0[i].valid) {
            add_free_frame(proc->pt0[i].pfn);
            proc->pt0[i].valid = 0;
        }
    }

    /* Free kernel stack pages */
    for (i = kstack_base_vpn; i < kstack_base_vpn + KERNEL_STACK_PAGES; i++) {
        if (proc->pt0[i].valid) {
            add_free_frame(proc->pt0[i].pfn);
            proc->pt0[i].valid = 0;
        }
    }

    /* Orphan all children */
    int j;
    for (j = 0; j < next_pid; j++) {
        if (procs[j].parent_pid == proc->pid) {
            procs[j].parent_pid = -1;
            if (procs[j].state == PROC_ZOMBIE) {
                procs[j].state = PROC_FREE;
            }
        }
    }

    /* Report to parent */
    PCB *parent = NULL;
    if (proc->parent_pid >= 0) {
        parent = find_pcb(proc->parent_pid);
    }

    if (parent && parent->state != PROC_FREE && parent->state != PROC_ZOMBIE) {
        ZombieNode *zn = (ZombieNode *)malloc(sizeof(ZombieNode));
        if (zn) {
            zn->pid = proc->pid;
            zn->status = status;
            zn->next = parent->zombie_children;
            parent->zombie_children = zn;
        }
        if (parent->state == PROC_BLOCKED) {
            enqueue_ready(parent);
        }
    }

    /* Free page table frame */
    unsigned int pt0_pfn = (unsigned int)(proc->pt0_phys >> PAGESHIFT);
    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        if (kernel_pt1[i].valid && kernel_pt1[i].pfn == pt0_pfn) {
            if ((struct pte *)(unsigned long)(VMEM_1_BASE + ((unsigned long)i << PAGESHIFT)) == proc->pt0) {
                kernel_pt1[i].valid = 0;
                WriteRegister(REG_TLB_FLUSH,
                    (RCS421RegVal)(VMEM_1_BASE + ((unsigned long)i << PAGESHIFT)));
                add_free_frame(pt0_pfn);
                break;
            }
        }
    }

    if (parent && parent->state != PROC_FREE) {
        proc->state = PROC_ZOMBIE;
    } else {
        proc->state = PROC_FREE;
    }
    proc->exit_status = status;
}

/* ============================================================
 * Switch to next process after terminating current
 * ============================================================ */
static void
switch_after_terminate(ExceptionInfo *info)
{
    if (!any_live_processes()) {
        TracePrintf(0, "No more processes. Halting.\n");
        Halt();
    }

    PCB *next = dequeue_ready();
    if (!next) next = idle_proc;
    PCB *old = current_proc;
    current_proc = next;
    next->state = PROC_RUNNING;
    next->clock_ticks = 0;
    (void)info;
    ContextSwitch(MySwitchFunc, &old->ctx, (void *)old, (void *)next);
}

/* ============================================================
 * Pointer Validation Helpers
 * ============================================================ */

static int
validate_buf(void *buf, int len, int write)
{
    if (len == 0) return 0;
    if (buf == NULL) return -1;

    unsigned long start = (unsigned long)buf;
    unsigned long end = start + len - 1;
    if (start >= KERNEL_STACK_BASE || end >= KERNEL_STACK_BASE) return -1;
    if (start < MEM_INVALID_SIZE) return -1;

    unsigned long page;
    for (page = (unsigned long)DOWN_TO_PAGE(start);
         page <= (unsigned long)DOWN_TO_PAGE(end);
         page += PAGESIZE) {
        int vpn = page >> PAGESHIFT;
        if (vpn < 0 || vpn >= PAGE_TABLE_LEN) return -1;
        if (!current_proc->pt0[vpn].valid) return -1;
        if (write && !(current_proc->pt0[vpn].uprot & PROT_WRITE)) return -1;
        if (!write && !(current_proc->pt0[vpn].uprot & PROT_READ)) return -1;
    }
    return 0;
}

static int
validate_string(char *str)
{
    if (str == NULL) return -1;
    unsigned long addr = (unsigned long)str;
    if (addr < MEM_INVALID_SIZE || addr >= KERNEL_STACK_BASE) return -1;

    while (1) {
        int vpn = addr >> PAGESHIFT;
        if (vpn >= (int)(KERNEL_STACK_BASE >> PAGESHIFT)) return -1;
        if (!current_proc->pt0[vpn].valid) return -1;
        if (!(current_proc->pt0[vpn].uprot & PROT_READ)) return -1;
        if (*(char *)addr == '\0') return 0;
        addr++;
    }
}

/* ============================================================
 * LoadProgram
 * ============================================================ */

static int
LoadProgram(char *name, char **args, ExceptionInfo *info)
{
    int fd;
    int status;
    struct loadinfo li;
    char *cp;
    char *cp2;
    char **cpp;
    char *argbuf;
    int i;
    unsigned long argcount;
    int size;
    int text_npg;
    int data_bss_npg;
    int stack_npg;

    TracePrintf(0, "LoadProgram '%s', args %p\n", name, args);

    if ((fd = open(name, O_RDONLY)) < 0) {
        TracePrintf(0, "LoadProgram: can't open file '%s'\n", name);
        return (-1);
    }

    status = LoadInfo(fd, &li);
    TracePrintf(0, "LoadProgram: LoadInfo status %d\n", status);
    switch (status) {
        case LI_SUCCESS: break;
        case LI_FORMAT_ERROR:
            TracePrintf(0, "LoadProgram: '%s' not in Yalnix format\n", name);
            close(fd); return (-1);
        case LI_OTHER_ERROR:
            TracePrintf(0, "LoadProgram: '%s' other error\n", name);
            close(fd); return (-1);
        default:
            TracePrintf(0, "LoadProgram: '%s' unknown error\n", name);
            close(fd); return (-1);
    }
    TracePrintf(0, "text_size 0x%lx, data_size 0x%lx, bss_size 0x%lx\n",
        li.text_size, li.data_size, li.bss_size);
    TracePrintf(0, "entry 0x%lx\n", li.entry);

    size = 0;
    for (i = 0; args[i] != NULL; i++) {
        size += strlen(args[i]) + 1;
    }
    argcount = i;
    TracePrintf(0, "LoadProgram: size %d, argcount %d\n", size, (int)argcount);

    cp = argbuf = (char *)malloc(size);
    if (!argbuf) { close(fd); return (-1); }
    for (i = 0; args[i] != NULL; i++) {
        strcpy(cp, args[i]);
        cp += strlen(cp) + 1;
    }

    cp = ((char *)USER_STACK_LIMIT) - size;
    cpp = (char **)((unsigned long)cp & ~(unsigned long)0xF);
    cpp = (char **)((unsigned long)cpp - ((argcount + 4) * sizeof(void *)));

    text_npg = li.text_size >> PAGESHIFT;
    data_bss_npg = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT;
    stack_npg = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;

    TracePrintf(0, "LoadProgram: text_npg %d, data_bss_npg %d, stack_npg %d\n",
        text_npg, data_bss_npg, stack_npg);

    if (MEM_INVALID_PAGES + text_npg + data_bss_npg + 1 + stack_npg +
        1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) {
        TracePrintf(0, "LoadProgram: program '%s' size too large for VIRTUAL memory\n", name);
        free(argbuf); close(fd); return (-1);
    }

    int pages_needed = text_npg + data_bss_npg + stack_npg;
    int pages_to_free = count_user_pages(current_proc->pt0);
    if (pages_needed - pages_to_free > get_num_free_frames()) {
        TracePrintf(0, "LoadProgram: program '%s' size too large for PHYSICAL memory\n", name);
        free(argbuf); close(fd); return (-1);
    }

    info->sp = (void *)cpp;

    /* Free all old Region 0 pages except kernel stack */
    int kstack_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
    for (i = 0; i < kstack_base_vpn; i++) {
        if (current_proc->pt0[i].valid) {
            add_free_frame(current_proc->pt0[i].pfn);
            current_proc->pt0[i].valid = 0;
        }
    }

    /* Set up text pages */
    int vpn = MEM_INVALID_PAGES;
    for (i = 0; i < text_npg; i++, vpn++) {
        int pfn = alloc_frame();
        current_proc->pt0[vpn].valid = 1;
        current_proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        current_proc->pt0[vpn].uprot = PROT_READ | PROT_EXEC;
        current_proc->pt0[vpn].pfn = pfn;
    }

    /* Set up data+bss pages */
    for (i = 0; i < data_bss_npg; i++, vpn++) {
        int pfn = alloc_frame();
        current_proc->pt0[vpn].valid = 1;
        current_proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        current_proc->pt0[vpn].uprot = PROT_READ | PROT_WRITE;
        current_proc->pt0[vpn].pfn = pfn;
    }

    current_proc->brk = (void *)((unsigned long)(MEM_INVALID_SIZE) +
        (unsigned long)(text_npg + data_bss_npg) * PAGESIZE);

    /* Set up stack pages */
    int stack_base_vpn = (USER_STACK_LIMIT >> PAGESHIFT) - stack_npg;
    for (i = 0; i < stack_npg; i++) {
        int pfn = alloc_frame();
        current_proc->pt0[stack_base_vpn + i].valid = 1;
        current_proc->pt0[stack_base_vpn + i].kprot = PROT_READ | PROT_WRITE;
        current_proc->pt0[stack_base_vpn + i].uprot = PROT_READ | PROT_WRITE;
        current_proc->pt0[stack_base_vpn + i].pfn = pfn;
    }

    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size + li.data_size)
        != (ssize_t)(li.text_size + li.data_size)) {
        TracePrintf(0, "LoadProgram: couldn't read for '%s'\n", name);
        free(argbuf); close(fd); return (-2);
    }
    close(fd);

    /* Set text pages to read/execute */
    vpn = MEM_INVALID_PAGES;
    for (i = 0; i < text_npg; i++, vpn++) {
        current_proc->pt0[vpn].kprot = PROT_READ | PROT_EXEC;
    }
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size),
        '\0', li.bss_size);

    info->pc = li.entry;

    *cpp++ = (char *)argcount;
    cp2 = argbuf;
    for (i = 0; (unsigned long)i < argcount; i++) {
        *cpp++ = cp;
        strcpy(cp, cp2);
        cp += strlen(cp) + 1;
        cp2 += strlen(cp2) + 1;
    }
    free(argbuf);
    *cpp++ = NULL;
    *cpp++ = NULL;
    *cpp++ = 0;

    for (i = 0; i < NUM_REGS; i++) info->regs[i] = 0;
    info->psr = 0;

    return (0);
}

/* ============================================================
 * Trap Handlers
 * ============================================================ */

static void
trap_kernel_handler(ExceptionInfo *info)
{
    int call_num = info->code;
    TracePrintf(1, "TRAP_KERNEL: pid %d, call %d\n", current_proc->pid, call_num);

    switch (call_num) {
    case YALNIX_FORK: {
        PCB *child = alloc_pcb();
        if (!child) { info->regs[0] = ERROR; break; }

        unsigned long child_pt0_phys;
        struct pte *child_pt0 = alloc_page_table(&child_pt0_phys);
        if (!child_pt0) { info->regs[0] = ERROR; break; }
        child->pt0 = child_pt0;
        child->pt0_phys = child_pt0_phys;

        int pages_needed = 0;
        int i;
        for (i = 0; i < PAGE_TABLE_LEN; i++) {
            if (current_proc->pt0[i].valid) pages_needed++;
        }

        if (pages_needed > get_num_free_frames()) {
            TracePrintf(0, "Fork: not enough memory\n");
            unsigned int pt_pfn = (unsigned int)(child_pt0_phys >> PAGESHIFT);
            int j;
            for (j = 0; j < PAGE_TABLE_LEN; j++) {
                if (kernel_pt1[j].valid && kernel_pt1[j].pfn == pt_pfn &&
                    (struct pte *)(unsigned long)(VMEM_1_BASE + ((unsigned long)j << PAGESHIFT)) == child_pt0) {
                    kernel_pt1[j].valid = 0;
                    WriteRegister(REG_TLB_FLUSH,
                        (RCS421RegVal)(VMEM_1_BASE + ((unsigned long)j << PAGESHIFT)));
                    break;
                }
            }
            add_free_frame(pt_pfn);
            info->regs[0] = ERROR;
            break;
        }

        for (i = 0; i < PAGE_TABLE_LEN; i++) {
            if (current_proc->pt0[i].valid) {
                int pfn = alloc_frame();
                child_pt0[i].valid = 1;
                child_pt0[i].kprot = current_proc->pt0[i].kprot;
                child_pt0[i].uprot = current_proc->pt0[i].uprot;
                child_pt0[i].pfn = pfn;
            } else {
                child_pt0[i].valid = 0;
            }
        }

        child->brk = current_proc->brk;
        child->parent_pid = current_proc->pid;
        current_proc->num_children++;

        int rc = ContextSwitch(ForkSwitchFunc, &current_proc->ctx,
            (void *)current_proc, (void *)child);
        if (rc < 0) {
            TracePrintf(0, "Fork: ContextSwitch failed\n");
            info->regs[0] = ERROR;
            break;
        }

        if (current_proc->pid == child->pid) {
            info->regs[0] = 0;
        } else {
            child->state = PROC_READY;
            enqueue_ready(child);
            info->regs[0] = child->pid;
        }
        break;
    }

    case YALNIX_EXEC: {
        char *filename = (char *)info->regs[1];
        char **argvec = (char **)info->regs[2];
        int i;

        if (validate_string(filename) < 0) {
            info->regs[0] = ERROR; break;
        }
        if (argvec == NULL) {
            info->regs[0] = ERROR; break;
        }

        int argc = 0;
        while (1) {
            if (validate_buf(&argvec[argc], sizeof(char *), 0) < 0) {
                info->regs[0] = ERROR; goto exec_done;
            }
            if (argvec[argc] == NULL) break;
            if (validate_string(argvec[argc]) < 0) {
                info->regs[0] = ERROR; goto exec_done;
            }
            argc++;
        }

        char **kargs = (char **)malloc((argc + 1) * sizeof(char *));
        if (!kargs) { info->regs[0] = ERROR; break; }
        for (i = 0; i < argc; i++) {
            kargs[i] = strdup(argvec[i]);
            if (!kargs[i]) {
                int j; for (j = 0; j < i; j++) free(kargs[j]);
                free(kargs);
                info->regs[0] = ERROR; goto exec_done;
            }
        }
        kargs[argc] = NULL;

        char *kfilename = strdup(filename);
        if (!kfilename) {
            for (i = 0; i < argc; i++) free(kargs[i]);
            free(kargs);
            info->regs[0] = ERROR; break;
        }

        int rc = LoadProgram(kfilename, kargs, info);
        free(kfilename);
        for (i = 0; i < argc; i++) free(kargs[i]);
        free(kargs);

        if (rc == -1) {
            info->regs[0] = ERROR;
        } else if (rc == -2) {
            terminate_process(current_proc, ERROR);
            switch_after_terminate(info);
        }
        break;
    exec_done:
        break;
    }

    case YALNIX_EXIT: {
        int exit_status = (int)info->regs[1];
        TracePrintf(0, "Exit: pid %d with status %d\n", current_proc->pid, exit_status);
        terminate_process(current_proc, exit_status);
        switch_after_terminate(info);
        break;
    }

    case YALNIX_WAIT: {
        int *status_ptr = (int *)info->regs[1];
        if (validate_buf(status_ptr, sizeof(int), 1) < 0) {
            info->regs[0] = ERROR; break;
        }

        int has_children = 0;
        int j;
        for (j = 0; j < next_pid; j++) {
            if (procs[j].parent_pid == current_proc->pid &&
                procs[j].state != PROC_FREE) {
                has_children = 1; break;
            }
        }
        if (!has_children && !current_proc->zombie_children) {
            info->regs[0] = ERROR; break;
        }

        if (current_proc->zombie_children) {
            ZombieNode *zn = current_proc->zombie_children;
            current_proc->zombie_children = zn->next;
            *status_ptr = zn->status;
            info->regs[0] = zn->pid;
            PCB *zombie = find_pcb(zn->pid);
            if (zombie) zombie->state = PROC_FREE;
            free(zn);
            current_proc->num_children--;
            break;
        }

        current_proc->state = PROC_BLOCKED;
        schedule(info);

        if (current_proc->zombie_children) {
            ZombieNode *zn = current_proc->zombie_children;
            current_proc->zombie_children = zn->next;
            *status_ptr = zn->status;
            info->regs[0] = zn->pid;
            PCB *zombie = find_pcb(zn->pid);
            if (zombie) zombie->state = PROC_FREE;
            free(zn);
            current_proc->num_children--;
        } else {
            info->regs[0] = ERROR;
        }
        break;
    }

    case YALNIX_GETPID:
        info->regs[0] = current_proc->pid;
        break;

    case YALNIX_BRK: {
        void *addr = (void *)info->regs[1];
        unsigned long new_brk = UP_TO_PAGE(addr);
        unsigned long old_brk = UP_TO_PAGE(current_proc->brk);

        TracePrintf(1, "Brk: pid %d, addr %p\n", current_proc->pid, addr);

        if ((unsigned long)addr < MEM_INVALID_SIZE) {
            info->regs[0] = ERROR; break;
        }

        /* Find lowest valid stack page */
        int lowest_stack_vpn = USER_STACK_LIMIT >> PAGESHIFT;
        int sv;
        for (sv = (int)(UP_TO_PAGE(current_proc->brk) >> PAGESHIFT);
             sv < (int)(USER_STACK_LIMIT >> PAGESHIFT); sv++) {
            if (current_proc->pt0[sv].valid) {
                lowest_stack_vpn = sv; break;
            }
        }

        if ((new_brk >> PAGESHIFT) + 1 > (unsigned long)lowest_stack_vpn) {
            info->regs[0] = ERROR; break;
        }

        if (new_brk > old_brk) {
            int pages_needed2 = (new_brk - old_brk) >> PAGESHIFT;
            if (pages_needed2 > get_num_free_frames()) {
                info->regs[0] = ERROR; break;
            }
            unsigned long page;
            for (page = old_brk; page < new_brk; page += PAGESIZE) {
                int vpn2 = page >> PAGESHIFT;
                int pfn = alloc_frame();
                current_proc->pt0[vpn2].valid = 1;
                current_proc->pt0[vpn2].kprot = PROT_READ | PROT_WRITE;
                current_proc->pt0[vpn2].uprot = PROT_READ | PROT_WRITE;
                current_proc->pt0[vpn2].pfn = pfn;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)page);
            }
        } else if (new_brk < old_brk) {
            unsigned long page;
            for (page = new_brk; page < old_brk; page += PAGESIZE) {
                int vpn2 = page >> PAGESHIFT;
                if (current_proc->pt0[vpn2].valid) {
                    add_free_frame(current_proc->pt0[vpn2].pfn);
                    current_proc->pt0[vpn2].valid = 0;
                    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)page);
                }
            }
        }
        current_proc->brk = addr;
        info->regs[0] = 0;
        break;
    }

    case YALNIX_DELAY: {
        int ticks = (int)info->regs[1];
        if (ticks < 0) { info->regs[0] = ERROR; break; }
        if (ticks == 0) { info->regs[0] = 0; break; }
        current_proc->delay_ticks = ticks;
        enqueue_delay(current_proc);
        info->regs[0] = 0;
        schedule(info);
        break;
    }

    case YALNIX_TTY_READ: {
        int tty_id = (int)info->regs[1];
        void *buf = (void *)info->regs[2];
        int len = (int)info->regs[3];

        if (tty_id < 0 || tty_id >= NUM_TERMINALS || len < 0) {
            info->regs[0] = ERROR; break;
        }
        if (len == 0) { info->regs[0] = 0; break; }
        if (validate_buf(buf, len, 1) < 0) {
            info->regs[0] = ERROR; break;
        }

        while (!tty_input_head[tty_id]) {
            current_proc->state = PROC_WAIT_TTY_READ;
            current_proc->next = tty_read_waiters[tty_id];
            tty_read_waiters[tty_id] = current_proc;
            schedule(info);
        }

        TtyBuf *tb = tty_input_head[tty_id];
        int avail = tb->len - tb->offset;
        int to_copy = (len < avail) ? len : avail;
        memcpy(buf, tb->data + tb->offset, to_copy);
        tb->offset += to_copy;

        if (tb->offset >= tb->len) {
            tty_input_head[tty_id] = tb->next;
            if (!tty_input_head[tty_id]) tty_input_tail[tty_id] = NULL;
            free(tb);
        }
        info->regs[0] = to_copy;
        break;
    }

    case YALNIX_TTY_WRITE: {
        int tty_id = (int)info->regs[1];
        void *buf = (void *)info->regs[2];
        int len = (int)info->regs[3];

        if (tty_id < 0 || tty_id >= NUM_TERMINALS || len < 0 ||
            len > TERMINAL_MAX_LINE) {
            info->regs[0] = ERROR; break;
        }
        if (len == 0) { info->regs[0] = 0; break; }
        if (validate_buf(buf, len, 0) < 0) {
            info->regs[0] = ERROR; break;
        }

        /* Copy user data to kernel buffer and transmit */
        memcpy(tty_transmit_buf[tty_id], buf, len);
        TtyTransmit(tty_id, tty_transmit_buf[tty_id], len);

        /* Return success */
        info->regs[0] = len;
        break;
    }

    default:
        TracePrintf(0, "TRAP_KERNEL: unknown call %d\n", call_num);
        info->regs[0] = ERROR;
        break;
    }
}

static void
trap_clock_handler(ExceptionInfo *info)
{
    TracePrintf(2, "TRAP_CLOCK: pid %d\n", current_proc->pid);

    PCB *prev = NULL;
    PCB *p = delay_head;
    while (p) {
        p->delay_ticks--;
        PCB *next_p = p->next;
        if (p->delay_ticks <= 0) {
            if (prev) prev->next = next_p;
            else delay_head = next_p;
            enqueue_ready(p);
        } else {
            prev = p;
        }
        p = next_p;
    }

    current_proc->clock_ticks++;
    if (current_proc->clock_ticks >= CLOCK_QUANTUM && ready_head) {
        if (current_proc != idle_proc) {
            enqueue_ready(current_proc);
        }
        schedule(info);
    } else if (current_proc == idle_proc && ready_head) {
        schedule(info);
    }
}

static void
trap_illegal_handler(ExceptionInfo *info)
{
    TracePrintf(0, "TRAP_ILLEGAL: pid %d at pc %p, code %d\n",
        current_proc->pid, info->pc, info->code);
    fprintf(stderr, "TRAP_ILLEGAL: pid %d at pc %p\n",
        current_proc->pid, info->pc);

    if (current_proc == idle_proc) {
        TracePrintf(0, "Idle process killed. Halting.\n");
        Halt();
    }
    terminate_process(current_proc, ERROR);
    switch_after_terminate(info);
}

static void
trap_memory_handler(ExceptionInfo *info)
{
    unsigned long addr = (unsigned long)info->addr;
    TracePrintf(1, "TRAP_MEMORY: pid %d, addr %p, code %d\n",
        current_proc->pid, info->addr, info->code);

    /* Check if stack growth request */
    if (addr >= MEM_INVALID_SIZE && addr < KERNEL_STACK_BASE) {
        unsigned long brk_page = UP_TO_PAGE(current_proc->brk);
        unsigned long addr_page = DOWN_TO_PAGE(addr);

        if (addr_page >= brk_page + PAGESIZE) {
            /* Find current stack bottom */
            int stack_bottom_vpn = USER_STACK_LIMIT >> PAGESHIFT;
            int sv;
            for (sv = (int)(addr_page >> PAGESHIFT);
                 sv < (int)(USER_STACK_LIMIT >> PAGESHIFT); sv++) {
                if (current_proc->pt0[sv].valid) {
                    stack_bottom_vpn = sv;
                    break;
                }
            }

            int target_vpn = addr_page >> PAGESHIFT;
            int pages_needed = stack_bottom_vpn - target_vpn;
            if (pages_needed <= 0) pages_needed = 0;

            if (pages_needed > 0 && pages_needed <= get_num_free_frames()) {
                int pv;
                for (pv = target_vpn; pv < stack_bottom_vpn; pv++) {
                    if (!current_proc->pt0[pv].valid) {
                        int pfn = alloc_frame();
                        current_proc->pt0[pv].valid = 1;
                        current_proc->pt0[pv].kprot = PROT_READ | PROT_WRITE;
                        current_proc->pt0[pv].uprot = PROT_READ | PROT_WRITE;
                        current_proc->pt0[pv].pfn = pfn;
                        WriteRegister(REG_TLB_FLUSH,
                            (RCS421RegVal)((unsigned long)pv << PAGESHIFT));
                    }
                }
                return;
            }
        }
    }

    TracePrintf(0, "TRAP_MEMORY: killing pid %d, addr %p\n",
        current_proc->pid, info->addr);
    fprintf(stderr, "TRAP_MEMORY: pid %d killed, addr %p\n",
        current_proc->pid, info->addr);

    if (current_proc == idle_proc) {
        TracePrintf(0, "Idle process killed. Halting.\n");
        Halt();
    }
    terminate_process(current_proc, ERROR);
    switch_after_terminate(info);
}

static void
trap_math_handler(ExceptionInfo *info)
{
    TracePrintf(0, "TRAP_MATH: pid %d at pc %p\n", current_proc->pid, info->pc);
    fprintf(stderr, "TRAP_MATH: pid %d at pc %p\n", current_proc->pid, info->pc);

    if (current_proc == idle_proc) {
        TracePrintf(0, "Idle process killed. Halting.\n");
        Halt();
    }
    terminate_process(current_proc, ERROR);
    switch_after_terminate(info);
}

static void
trap_tty_receive_handler(ExceptionInfo *info)
{
    int tty_id = info->code;
    TracePrintf(1, "TRAP_TTY_RECEIVE: tty %d\n", tty_id);
    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return;

    TtyBuf *tb = (TtyBuf *)malloc(sizeof(TtyBuf));
    if (!tb) return;
    tb->len = TtyReceive(tty_id, tb->data, TERMINAL_MAX_LINE);
    tb->offset = 0;
    tb->next = NULL;

    if (tty_input_tail[tty_id]) {
        tty_input_tail[tty_id]->next = tb;
    } else {
        tty_input_head[tty_id] = tb;
    }
    tty_input_tail[tty_id] = tb;

    if (tty_read_waiters[tty_id]) {
        PCB *waiter = tty_read_waiters[tty_id];
        tty_read_waiters[tty_id] = waiter->next;
        waiter->next = NULL;
        enqueue_ready(waiter);
    }
}

static void
trap_tty_transmit_handler(ExceptionInfo *info)
{
    int tty_id = info->code;
    TracePrintf(1, "TRAP_TTY_TRANSMIT: tty %d\n", tty_id);
    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return;

    /* Wake up the process waiting for this TTY write to complete */
    int i;
    for (i = 0; i < next_pid; i++) {
        if (procs[i].state == PROC_WAIT_TTY_WRITE) {
            enqueue_ready(&procs[i]);
            break;
        }
    }
}

static void
trap_disk_handler(ExceptionInfo *info)
{
    (void)info;
}

/* ============================================================
 * SetKernelBrk
 * ============================================================ */

int
SetKernelBrk(void *addr)
{
    TracePrintf(1, "SetKernelBrk: addr %p, vm_enabled %d\n", addr, vm_enabled);

    if (!vm_enabled) {
        kernel_brk = addr;
        return 0;
    }

    unsigned long new_brk = UP_TO_PAGE(addr);
    unsigned long old_brk = UP_TO_PAGE(kernel_brk);

    if (new_brk > old_brk) {
        int pages_needed = (new_brk - old_brk) >> PAGESHIFT;
        if (pages_needed > get_num_free_frames()) return -1;

        unsigned long page;
        for (page = old_brk; page < new_brk; page += PAGESIZE) {
            int vpn = (page - VMEM_1_BASE) >> PAGESHIFT;
            if (vpn >= 0 && vpn < PAGE_TABLE_LEN && !kernel_pt1[vpn].valid) {
                int pfn = alloc_frame();
                if (pfn < 0) return -1;
                kernel_pt1[vpn].valid = 1;
                kernel_pt1[vpn].kprot = PROT_READ | PROT_WRITE;
                kernel_pt1[vpn].uprot = PROT_NONE;
                kernel_pt1[vpn].pfn = pfn;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)page);
            }
        }
    } else if (new_brk < old_brk) {
        unsigned long page;
        for (page = new_brk; page < old_brk; page += PAGESIZE) {
            int vpn = (page - VMEM_1_BASE) >> PAGESHIFT;
            if (vpn >= 0 && vpn < PAGE_TABLE_LEN && kernel_pt1[vpn].valid) {
                add_free_frame(kernel_pt1[vpn].pfn);
                kernel_pt1[vpn].valid = 0;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)page);
            }
        }
    }

    kernel_brk = addr;
    return 0;
}

/* ============================================================
 * KernelStart
 * ============================================================ */

void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    int i;

    TracePrintf(0, "KernelStart: info %p, pmem_size %x, orig_brk %p\n",
        info, pmem_size, orig_brk);
    TracePrintf(0, "KernelStart: cmd_args %p\n", cmd_args);
    if (cmd_args) {
        for (i = 0; cmd_args[i]; i++) {
            TracePrintf(0, "cmd_args[%d] = %p = '%s'\n", i, cmd_args[i], cmd_args[i]);
        }
    }
    TracePrintf(0, "addr %p, pc %p, sp %p\n", info->addr, info->pc, info->sp);
    TracePrintf(0, "info: vector %d, code %d\n", info->vector, info->code);

    boot_info = info;
    kernel_brk = orig_brk;
    num_phys_pages = pmem_size / PAGESIZE;

    TracePrintf(0, "KernelStart: num_phys_pages=%d\n", num_phys_pages);

    /* ---- Initialize interrupt vector table ---- */
    for (i = 0; i < TRAP_VECTOR_SIZE; i++) interrupt_vector[i] = NULL;
    interrupt_vector[TRAP_KERNEL] = trap_kernel_handler;
    interrupt_vector[TRAP_CLOCK] = trap_clock_handler;
    interrupt_vector[TRAP_ILLEGAL] = trap_illegal_handler;
    interrupt_vector[TRAP_MEMORY] = trap_memory_handler;
    interrupt_vector[TRAP_MATH] = trap_math_handler;
    interrupt_vector[TRAP_TTY_RECEIVE] = trap_tty_receive_handler;
    interrupt_vector[TRAP_TTY_TRANSMIT] = trap_tty_transmit_handler;
    interrupt_vector[TRAP_DISK] = trap_disk_handler;

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)interrupt_vector);

    /* ---- Initialize TTY state ---- */
    for (i = 0; i < NUM_TERMINALS; i++) {
        tty_input_head[i] = NULL;
        tty_input_tail[i] = NULL;
        tty_read_waiters[i] = NULL;
        tty_transmit_busy[i] = 0;
        tty_write_head[i] = NULL;
        tty_write_tail[i] = NULL;
    }

    /* ---- Build initial page tables ---- */
    unsigned long brk_page = UP_TO_PAGE(kernel_brk);
    kernel_pt1 = (struct pte *)brk_page;
    initial_pt0 = (struct pte *)(brk_page + PAGE_TABLE_SIZE);
    kernel_brk = (void *)(brk_page + PAGESIZE);
    if (PAGE_TABLE_SIZE * 2 > PAGESIZE) {
        kernel_brk = (void *)(brk_page + UP_TO_PAGE(PAGE_TABLE_SIZE * 2));
    }

    memset(kernel_pt1, 0, PAGE_TABLE_SIZE);
    memset(initial_pt0, 0, PAGE_TABLE_SIZE);

    /* Set up Region 1 (kernel) page table */
    unsigned long kernel_text_end = (unsigned long)&_etext;
    unsigned long kernel_data_end = UP_TO_PAGE(kernel_brk);

    TracePrintf(0, "kernel text end: %lx, data end: %lx\n",
        kernel_text_end, kernel_data_end);

    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long vaddr = VMEM_1_BASE + ((unsigned long)i << PAGESHIFT);
        if (vaddr < kernel_text_end) {
            kernel_pt1[i].valid = 1;
            kernel_pt1[i].kprot = PROT_READ | PROT_EXEC;
            kernel_pt1[i].uprot = PROT_NONE;
            kernel_pt1[i].pfn = vaddr >> PAGESHIFT;
        } else if (vaddr < kernel_data_end) {
            kernel_pt1[i].valid = 1;
            kernel_pt1[i].kprot = PROT_READ | PROT_WRITE;
            kernel_pt1[i].uprot = PROT_NONE;
            kernel_pt1[i].pfn = vaddr >> PAGESHIFT;
        }
    }
    kernel_pt1_phys = (unsigned long)kernel_pt1;

    /* Also mark the page containing DoIdle as user-executable */
    unsigned long idle_addr = (unsigned long)DoIdle;
    int idle_vpn = (idle_addr - VMEM_1_BASE) >> PAGESHIFT;
    kernel_pt1[idle_vpn].uprot = PROT_READ | PROT_EXEC;

    /* Set up Region 0 (initial process) page table - kernel stack */
    int kstack_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int vpn = kstack_base_vpn + i;
        initial_pt0[vpn].valid = 1;
        initial_pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        initial_pt0[vpn].uprot = PROT_NONE;
        initial_pt0[vpn].pfn = vpn;
    }

    unsigned long initial_pt0_phys = (unsigned long)initial_pt0;
    WriteRegister(REG_PTR0, (RCS421RegVal)initial_pt0_phys);
    WriteRegister(REG_PTR1, (RCS421RegVal)kernel_pt1_phys);

    /* ---- Enable virtual memory ---- */
    WriteRegister(REG_VM_ENABLE, 1);
    vm_enabled = 1;
    TracePrintf(0, "KernelStart: VM enabled\n");

    /* ---- Build free frame list ---- */
    init_free_frames(num_phys_pages);
    for (i = 0; i < num_phys_pages; i++) {
        int used = 0;
        int j;
        for (j = 0; j < PAGE_TABLE_LEN; j++) {
            if (kernel_pt1[j].valid && kernel_pt1[j].pfn == (unsigned int)i) {
                used = 1; break;
            }
        }
        if (!used) {
            for (j = 0; j < PAGE_TABLE_LEN; j++) {
                if (initial_pt0[j].valid && initial_pt0[j].pfn == (unsigned int)i) {
                    used = 1; break;
                }
            }
        }
        if (!used) add_free_frame(i);
    }
    TracePrintf(0, "KernelStart: %d free frames\n", num_free_frames);

    /* ---- Create idle process (pid 0) ---- */
    idle_proc = alloc_pcb();
    idle_proc->pt0 = initial_pt0;
    idle_proc->pt0_phys = initial_pt0_phys;
    idle_proc->state = PROC_RUNNING;
    current_proc = idle_proc;

    /* Allocate a user stack page for idle in Region 0 */
    {
        int user_stack_vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
        int pfn = alloc_frame();
        if (pfn < 0) {
            TracePrintf(0, "KernelStart: no frame for idle user stack\n");
            Halt();
        }
        initial_pt0[user_stack_vpn].valid = 1;
        initial_pt0[user_stack_vpn].kprot = PROT_READ | PROT_WRITE;
        initial_pt0[user_stack_vpn].uprot = PROT_READ | PROT_WRITE;
        initial_pt0[user_stack_vpn].pfn = pfn;
        WriteRegister(REG_TLB_FLUSH,
            (RCS421RegVal)((unsigned long)user_stack_vpn << PAGESHIFT));
    }

    /* ---- Create init process (pid 1) ---- */
    PCB *init_proc = alloc_pcb();
    unsigned long init_pt0_phys;
    struct pte *init_pt0 = alloc_page_table(&init_pt0_phys);
    if (!init_pt0) {
        TracePrintf(0, "KernelStart: cannot allocate page table for init\n");
        Halt();
    }
    init_proc->pt0 = init_pt0;
    init_proc->pt0_phys = init_pt0_phys;

    /* Allocate kernel stack pages for init */
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int vpn = kstack_base_vpn + i;
        int pfn = alloc_frame();
        if (pfn < 0) {
            TracePrintf(0, "KernelStart: cannot allocate kernel stack for init\n");
            Halt();
        }
        init_pt0[vpn].valid = 1;
        init_pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        init_pt0[vpn].uprot = PROT_NONE;
        init_pt0[vpn].pfn = pfn;
    }

    /* Clone kernel stack from idle to init */
    int rc = ContextSwitch(CloneInitFunc, &idle_proc->ctx,
        (void *)idle_proc, (void *)init_proc);
    if (rc < 0) {
        TracePrintf(0, "KernelStart: ContextSwitch for init clone failed\n");
        Halt();
    }

    /*
     * After ContextSwitch returns here, we might be:
     * (a) The initial boot run (idle_initialized == 0), OR
     * (b) Idle being switched to for the first time later (idle_initialized == 1).
     *
     * Case (b): idle returns here from ContextSwitch. We need to set up info
     * to run the DoIdle function, then return from KernelStart. The hardware
     * will restore the ExceptionInfo and idle will run DoIdle.
     */
    if (idle_initialized) {
        /* We're idle, just returned from being context-switched to */
        TracePrintf(0, "Bottom of KernelStart: idle returning\n");
        info->pc = (void *)DoIdle;
        info->sp = (void *)(USER_STACK_LIMIT - 4 * sizeof(void *));
        info->psr = 0; /* user mode */
        int k;
        for (k = 0; k < NUM_REGS; k++) info->regs[k] = 0;
        return;
    }
    idle_initialized = 1;

    /* Switch to init's address space and load the program */
    WriteRegister(REG_PTR0, (RCS421RegVal)init_pt0_phys);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    current_proc = init_proc;

    char *init_name = "init";
    char **init_args = cmd_args;
    if (cmd_args && cmd_args[0]) {
        init_name = cmd_args[0];
    } else {
        static char *default_args[] = { "init", NULL };
        init_args = default_args;
    }

    TracePrintf(0, "KernelStart: loading init program '%s'\n", init_name);
    rc = LoadProgram(init_name, init_args, info);
    if (rc < 0) {
        TracePrintf(0, "KernelStart: LoadProgram failed for '%s'\n", init_name);
        Halt();
    }

    init_proc->state = PROC_RUNNING;
    idle_proc->state = PROC_READY;

    TracePrintf(0, "Bottom of KernelStart:\n");
}

